from typing import List

class Solution:
    def solve(self, edges: List[List[int]]) -> int: 
        visited = [False] * len(edges) 
        for i in range(len(edges)): 
            if not visited[i]: 
                self._dfs(i, visited) 
        for i in range(len(edges)): 
            if visited[i] and (sum([1 for neighbor in edges[j] if i == neighbor]) % 2 != 0): 
                return 1
        return 0

    def _dfs(self, node, visited): 
        if visited[node]: 
            return 
        visited[node] = True 
        for neighbor in edges[node]: 
            if visited[neighbor]: 
                visited = [False] * len(edges) 
        return

