#include <iostream> 
#include <vector> 

using namespace std; 

class Solution {
 public: 
 void solve(vector<vector<int>>& edges){ 
     bool visited[edges.size()]; 
     memset(visited, false, sizeof(visited)); 
     for(int i = 0; i < edges.size(); i++){ 
         if(!visited[i]) 
             _dfs(i, visited); 
     } 
     for(int i = 0; i < edges.size(); i++){ 
         if(visited[i] && (sumOfIncomingEdges(i, edges) % 2 != 0)) 
             return 1; 
     } 
     return 0; 
 } 
 int sumOfIncomingEdges(int node, vector<vector<int>>& edges){ 
     int count = 0; 
     for(int i = 0; i < edges.size(); i++){ 
         for(int neighbor : edges[i]){ 
             if(node == neighbor) 
                 count++; 
         } 
     } 
     return count; 
 } 
 void _dfs(int node, bool visited[]){ 
     if(visited[node]){ 
         return; 
     } 
     visited[node] = true; 
     for(int neighbor : edges[node]){ 
         if(visited[neighbor]){ 
             memset(visited, false, sizeof(visited)); 
         } 
     } 
 } 
}; 
 int main(){ 
     Solution solution; 
     vector<vector<int>> edges = {{1, 2}, {2, 3}, {3, 4}, {4, 1}}; 
     cout << solution.solve(edges) << endl; 
     return 0; 
}
